+	if string(got) != string(payload) {
+		t.Fatalf("raw decoded = %q, want %q", got, payload)
+	}
+
+	padded := base64.URLEncoding.EncodeToString(payload)
+	got, err = decodeGmailRaw(padded)
+	if err != nil {
+		t.Fatalf("decodeGmailRaw padded: %v", err)
+	}
